   292	        }
   293	        attrs
   294	    }
   295	
   296	    /// Attrs for the optional visual indicator (e.g., chevron) showing open/closed state.
   297	    pub fn indicator_attrs(&self) -> AttrMap {
   298	        let mut attrs = AttrMap::new();
