   332	        }
   333	        if has_collapsed_size {
   334	            attrs.set_bool(HtmlAttr::Data("ars-collapsed-size"), true);
   335	        }
   336	        attrs.set(HtmlAttr::Data("ars-state"), if self.is_open() { "open" } else { "closed" });
   337	        attrs
   338	    }
